class Solution {
    public int uniqueBinarySearchTrees(int data) {
        return countTrees(1, data);
    }
    private int countTrees(int start, int end) {
        if (start > end) {
            return 1;
        }
        int totalTrees = 0;
        for (int root = start; root <= end; root++) {
            int leftTrees = countTrees(start, root - 1);
            int rightTrees = countTrees(root + 1, end);
            totalTrees += leftTrees * rightTrees;
        }
        return totalTrees;
    }
}

