func uniqueBinarySearchTrees(data int) int {
    if data <= 1 {
        return 1
    }
    count := make([]int, data+1)
    count[0], count[1] = 1, 1

    for i := 2; i <= data; i++ {
        for j := 0; j < i; j++ {
            count[i] += count[j] * count[i-j-1]
        }
    }
    return count[data]
}

