        dp[0] = 1; // Base case: empty tree
        dp[1] = 1; // Base case: one node
        for (int i = 2; i <= data; ++i) {
            for (int j = 1; j <= i; ++j) {
                dp[i] += dp[j - 1] * dp[i - j];
            }
        }
        return dp[data];
